2	import { buildUrlAndHeadersForRegistryItem } from "@/src/registry/builder"
3	import { configWithDefaults } from "@/src/registry/config"
4	import {
5	  BASE_COLORS,
6	  BUILTIN_REGISTRIES,
7	  REGISTRY_URL,
8	} from "@/src/registry/constants"
9	import {
10	  clearRegistryContext,
11	  setRegistryHeaders,
12	} from "@/src/registry/context"
13	import {
14	  ConfigParseError,
15	  RegistriesIndexParseError,
16	  RegistryInvalidNamespaceError,
17	  RegistryNotFoundError,
18	  RegistryParseError,
19	} from "@/src/registry/errors"
20	import { fetchRegistry } from "@/src/registry/fetcher"
21	import {
22	  fetchRegistryItems,
23	  resolveRegistryTree,
24	} from "@/src/registry/resolver"
25	import { isUrl } from "@/src/registry/utils"
26	import {
27	  configJsonSchema,
28	  iconsSchema,
29	  registriesIndexSchema,
30	  registriesSchema,
31	  registryBaseColorSchema,
32	  registryConfigSchema,
33	  registryIndexSchema,
34	  registryItemSchema,
35	  registrySchema,
36	  stylesSchema,
37	} from "@/src/schema"
38	import { Config, explorer } from "@/src/utils/get-config"
39	import { handleError } from "@/src/utils/handle-error"
40	import { logger } from "@/src/utils/logger"
41	import { z } from "zod"
42	
43	export async function getRegistry(
44	  name: string,
45	  options?: {
46	    config?: Partial<Config>
47	    useCache?: boolean
48	  }
49	) {
50	  const { config, useCache } = options || {}
51	
52	  if (isUrl(name)) {
53	    const [result] = await fetchRegistry([name], { useCache })
54	    try {
55	      return registrySchema.parse(result)
56	    } catch (error) {
57	      throw new RegistryParseError(name, error)
58	    }
59	  }
60	
61	  if (!name.startsWith("@")) {
62	    throw new RegistryInvalidNamespaceError(name)
63	  }
64	
65	  let registryName = name
66	  if (!registryName.endsWith("/registry")) {
67	    registryName = `${registryName}/registry`
68	  }
69	
70	  const urlAndHeaders = buildUrlAndHeadersForRegistryItem(
71	    registryName as `@${string}`,
72	    configWithDefaults(config)
73	  )
74	
75	  if (!urlAndHeaders?.url) {
76	    throw new RegistryNotFoundError(registryName)
77	  }
78	
79	  if (urlAndHeaders.headers && Object.keys(urlAndHeaders.headers).length > 0) {
80	    setRegistryHeaders({
81	      [urlAndHeaders.url]: urlAndHeaders.headers,
82	    })
83	  }
84	
85	  const [result] = await fetchRegistry([urlAndHeaders.url], { useCache })
86	
87	  try {
88	    return registrySchema.parse(result)
89	  } catch (error) {
90	    throw new RegistryParseError(registryName, error)
91	  }
92	}
93	
94	export async function getRegistryItems(
95	  items: string[],
96	  options?: {
97	    config?: Partial<Config>
98	    useCache?: boolean
99	  }
100	) {
101	  const { config, useCache = false } = options || {}
102	
103	  clearRegistryContext()
104	
105	  return fetchRegistryItems(items, configWithDefaults(config), { useCache })
106	}
107	
108	export async function resolveRegistryItems(
109	  items: string[],
110	  options?: {
111	    config?: Partial<Config>
112	    useCache?: boolean
113	  }
114	) {
115	  const { config, useCache = false } = options || {}
116	
117	  clearRegistryContext()
118	  return resolveRegistryTree(items, configWithDefaults(config), { useCache })
119	}
120	
121	export async function getRegistriesConfig(
122	  cwd: string,
123	  options?: { useCache?: boolean }
124	) {
125	  const { useCache = true } = options || {}
126	
127	  // Clear cache if requested
128	  if (!useCache) {
129	    explorer.clearCaches()
130	  }
131	
132	  const configResult = await explorer.search(cwd)
133	
134	  if (!configResult) {
135	    // Do not throw an error if the config is missing.
136	    // We still have access to the built-in registries.
137	    return {
138	      registries: BUILTIN_REGISTRIES,
139	    }
140	  }
141	
142	  // Parse just the registries field from the config
143	  const registriesConfig = z
144	    .object({
145	      registries: registryConfigSchema.optional(),
146	    })
147	    .safeParse(configResult.config)
148	
149	  if (!registriesConfig.success) {
150	    throw new ConfigParseError(cwd, registriesConfig.error)
151	  }
152	
153	  // Merge built-in registries with user registries
154	  return {
155	    registries: {
156	      ...BUILTIN_REGISTRIES,
157	      ...(registriesConfig.data.registries || {}),
158	    },
159	  }
160	}
161	
162	export async function getShadcnRegistryIndex() {
163	  try {
164	    const [result] = await fetchRegistry(["index.json"])
165	
166	    return registryIndexSchema.parse(result)
167	  } catch (error) {
168	    logger.error("\n")
169	    handleError(error)
170	  }
171	}
172	
173	export async function getRegistryStyles() {
174	  try {
175	    const [result] = await fetchRegistry(["styles/index.json"])
176	
177	    return stylesSchema.parse(result)
178	  } catch (error) {
179	    logger.error("\n")
180	    handleError(error)
181	    return []
182	  }
183	}
184	
185	export async function getRegistryIcons() {
186	  try {
187	    const [result] = await fetchRegistry(["icons/index.json"])
188	    return iconsSchema.parse(result)
189	  } catch (error) {
190	    handleError(error)
191	    return {}
192	  }
193	}
194	
195	export async function getRegistryBaseColors() {
196	  return BASE_COLORS
197	}
198	
199	export async function getRegistryBaseColor(baseColor: string) {
200	  try {
201	    const [result] = await fetchRegistry([`colors/${baseColor}.json`])
202	
203	    return registryBaseColorSchema.parse(result)
204	  } catch (error) {
205	    handleError(error)
206	  }
207	}
208	
209	/**
210	 * @deprecated This function is deprecated and will be removed in a future version.
211	 */
212	export async function resolveTree(
213	  index: z.infer<typeof registryIndexSchema>,
214	  names: string[]
215	) {
216	  const tree: z.infer<typeof registryIndexSchema> = []
217	
218	  for (const name of names) {
219	    const entry = index.find((entry) => entry.name === name)
220	
221	    if (!entry) {
222	      continue
223	    }
224	
225	    tree.push(entry)
226	
227	    if (entry.registryDependencies) {
228	      const dependencies = await resolveTree(index, entry.registryDependencies)
229	      tree.push(...dependencies)
230	    }
231	  }
232	
233	  return tree.filter(
234	    (component, index, self) =>
235	      self.findIndex((c) => c.name === component.name) === index
236	  )
237	}
238	
239	/**
240	 * @deprecated This function is deprecated and will be removed in a future version.
241	 */
242	export async function fetchTree(
243	  style: string,
244	  tree: z.infer<typeof registryIndexSchema>
245	) {
246	  try {
247	    const paths = tree.map((item) => `styles/${style}/${item.name}.json`)
248	    const results = await fetchRegistry(paths)
249	    return results.map((result) => registryItemSchema.parse(result))
250	  } catch (error) {
251	    handleError(error)
252	    return []
253	  }
254	}
255	
256	/**
257	 * @deprecated This function is deprecated and will be removed in a future version.
258	 */
259	export async function getItemTargetPath(
260	  config: Config,
261	  item: Pick<z.infer<typeof registryItemSchema>, "type">,
262	  override?: string
263	) {
264	  if (override) {
265	    return override
266	  }
267	
268	  if (item.type === "registry:ui") {
269	    return config.resolvedPaths.ui ?? config.resolvedPaths.components
270	  }
271	
272	  const [parent, type] = item.type?.split(":") ?? []
273	  if (!(parent in config.resolvedPaths)) {
274	    return null
275	  }
276	
277	  return path.join(
278	    config.resolvedPaths[parent as keyof typeof config.resolvedPaths],
279	    type
280	  )
281	}
282	
283	// Fetch registries with new schema (array of objects with name, homepage, url, featured).
284	export async function getRegistries(options?: { useCache?: boolean }) {
285	  options = {
286	    useCache: true,
287	    ...options,
288	  }
289	
290	  const url = `${REGISTRY_URL}/registries.json`
291	  const [data] = await fetchRegistry([url], {
292	    useCache: options.useCache,
293	  })
294	
295	  try {
296	    return registriesSchema.parse(data)
297	  } catch (error) {
298	    if (error instanceof z.ZodError) {
299	      throw new RegistriesIndexParseError(error)
300	    }
301	
302	    throw error
303	  }
304	}
305	
306	/**
307	 * @deprecated Use getRegistries() instead.
308	 */
309	export async function getRegistriesIndex(options?: { useCache?: boolean }) {
310	  // Fetch new format and transform to old Record<string, string> for backward compatibility.
311	  const registries = await getRegistries(options)
312	  if (!registries) return null
313	  return Object.fromEntries(registries.map((r) => [r.name, r.url])) as z.infer<
314	    typeof registriesIndexSchema
315	  >
316	}
317	
318	export async function getPresets(options?: { useCache?: boolean }) {
319	  options = {
320	    useCache: true,
321	    ...options,
322	  }
323	
324	  const url = `${REGISTRY_URL}/config.json`
325	  const [data] = await fetchRegistry([url], {
326	    useCache: options.useCache,
327	  })
328	
329	  const result = configJsonSchema.parse(data)
330	  return result.presets
331	}
332	
333	export async function getPreset(
334	  name: string,
335	  options?: { useCache?: boolean }
336	) {
337	  const presets = await getPresets(options)
338	  return (
339	    presets.find(
340	      (preset) => preset.name.toLowerCase() === name.toLowerCase()
341	    ) ?? null
342	  )
343	}
