        default: "bg-muted",
        line: "gap-1 bg-transparent",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)
```

---

## **7. UTILITY FUNCTION**

**Path:** `/apps/v4/lib/utils.ts`

```tsx
import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function absoluteUrl(path: string) {
  return `${process.env.NEXT_PUBLIC_APP_URL}${path}`
}
```

---

## **KEY PATTERNS IDENTIFIED FOR YOUR STEPPER COMPONENT**

### **1. Primitive-Wrapper Pattern**
- Wrap base-ui or radix-ui primitives with your own components
- Pass `data-slot` attributes for CSS targeting and debugging
- Use `cn()` utility to merge base classes with user overrides

### **2. Compound Component Structure**
- **Root:** Main container using `createContext` or Primitive.Root
- **Subcomponents:** Use with context hook for state sharing
- **Exports:** All sub-components exported together from single file

### **3. Context for State Sharing**
- Create `React.createContext<T>` with typed props
- Hook pattern: `useCarousel()` with error boundary
- Providers wrap children in root component

### **4. Orientation Handling**
```tsx
data-orientation={orientation}
className={cn(
  "group/tabs flex gap-2 data-horizontal:flex-col",
  className
)}
```
Uses data attributes + CSS selectors

### **5. CVA (Class Variance Authority) for Variants**
```tsx
const tabsListVariants = cva(baseClasses, {
  variants: { variant: {...}, size: {...} },
  defaultVariants: {...}
})
```
Export variants for reuse in other components

### **6. Type Safety**
```tsx
function Button({
  className,
  variant = "default",
  size = "default",
  ...props
}: ButtonPrimitive.Props & VariantProps<typeof buttonVariants>) {...}
```
Combine primitive types with CVA variant types

### **7. Data Attributes**
- `data-slot`: Identifies component structure for styling
- `data-orientation`: Horizontal/vertical orientation
- `data-variant`: Variant styling indicator
- Uses group selector syntax: `group/component-name`

### **8. Spread Props Pattern**
```tsx
function Accordion({ className, ...props }: AccordionPrimitive.Root.Props) {
  return (
    <AccordionPrimitive.Root
      {...props}
      className={cn(..., className)}
    />
  )
}
```
Allows all primitive props to flow through

---

## **Implementation Recommendations for Stepper**

1. **Create StepperContext** for shared state (activeStep, orientation)
2. **Use data-slot attributes** (`stepper`, `stepper-item`, `stepper-trigger`, `stepper-content`)
3. **Support orientation** via data-orientation and group selectors
4. **Export variants** via CVA for step indicators
5. **Use both base-ui and radix versions** if supporting multiple base libraries
6. **Keyboard handling** with useCallback and event handlers
7. **Aria attributes** for accessibility (aria-current, aria-disabled, aria-expanded)

