"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/registry/bases/base/lib/utils"

// ─── Stepper context ─────────────────────────────────────────────────────────

type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── StepperItem context ──────────────────────────────────────────────────────

type StepperItemContextProps = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  /** The step that is active by default (uncontrolled). */
  defaultStep?: number
  /** The currently active step (controlled). */
  activeStep?: number
  /** Called when the active step changes. */
  onStepChange?: (step: number) => void
  /** Layout direction of the step list. */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  defaultStep = 1,
  activeStep: activeStepProp,
  onStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [uncontrolledStep, setUncontrolledStep] = React.useState(defaultStep)

  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : uncontrolledStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) setUncontrolledStep(step)
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  return (
    <StepperContext.Provider value={{ activeStep, setActiveStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("group/stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperList ─────────────────────────────────────────────────────────────

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      role="tablist"
      data-slot="stepper-list"
      aria-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal" ? "flex-row items-center" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  /** The 1-based index of this step. */
  step: number
  /** When true, the step cannot be navigated to. */
  disabled?: boolean
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep } = useStepper()

  const isActive = activeStep === step
  const isCompleted = activeStep > step

  return (
    <StepperItemContext.Provider
      value={{ step, isActive, isCompleted, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-active={isActive ? "" : undefined}
        data-completed={isCompleted ? "" : undefined}
        data-disabled={disabled ? "" : undefined}
        className={cn("group/stepper-item flex items-center gap-2", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepper()
  const { step, isDisabled } = useStepperItem()

  return (
    <button
      type="button"
      role="tab"
      data-slot="stepper-trigger"
      disabled={isDisabled}
      onClick={() => setActiveStep(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-sm text-left outline-none",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── StepperIndicator ────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { isActive, isCompleted, step } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-active={isActive ? "" : undefined}
      data-completed={isCompleted ? "" : undefined}
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full",
        "border-2 text-sm font-medium transition-colors",
        "border-border bg-background text-foreground",
        "data-active:border-primary data-active:bg-primary data-active:text-primary-foreground",
        "data-completed:border-primary data-completed:bg-primary data-completed:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ??
        (isCompleted ? (
          <CheckIcon className="size-4" aria-hidden="true" />
        ) : (
          step
        ))}
    </span>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn("text-sm font-medium leading-none", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      role="none"
      data-slot="stepper-separator"
      className={cn(
        "bg-border transition-colors",
        orientation === "horizontal"
          ? "h-px min-w-8 flex-1"
          : "ms-4 h-8 w-px shrink-0",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ──────────────────────────────────────────────────────────

type StepperContentProps = React.ComponentProps<"div"> & {
  /**
   * The step this panel belongs to.  When omitted the value is inherited from
   * the nearest parent `<StepperItem>`.
   */
  step?: number
}

function StepperContent({
  step: stepProp,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { activeStep } = useStepper()
  const itemContext = React.useContext(StepperItemContext)
  const step = stepProp ?? itemContext?.step

  if (step === undefined || activeStep !== step) return null

  return (
    <div
      role="tabpanel"
      data-slot="stepper-content"
      className={cn("text-sm", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
